   237→        private static void SetThresholds(string thresholds)
   238→        {
   239→            int lowerPercentage;
   240→            int upperPercentage = (int)(upperThreshold * 100);
   241→            int s = thresholds.IndexOf(" ");
   242→            if (s == 0)
   243→            {
   244→                throw new ArgumentException("Threshold parameter set incorrectly.");
   245→            }
   246→            else if (s < 0)
   247→            {
   248→                if (!int.TryParse(thresholds, out lowerPercentage))
   249→                    throw new ArgumentException("Threshold parameter set incorrectly.");
   250→            }
   251→            else
   252→            {
   253→                if (!int.TryParse(thresholds.AsSpan(0, s), out lowerPercentage))
   254→                    throw new ArgumentException("Threshold parameter set incorrectly.");
   255→
   256→                if (!int.TryParse(thresholds.AsSpan(s + 1), out upperPercentage))
   257→                    throw new ArgumentException("Threshold parameter set incorrectly.");
   258→            }
   259→            lowerThreshold = lowerPercentage / 100.0;
   260→            upperThreshold = upperPercentage / 100.0;
   261→
   262→            if (lowerThreshold > 1.0)
   263→                lowerThreshold = 1.0;
   264→
   265→            if (lowerThreshold > upperThreshold)
   266→                upperThreshold = lowerThreshold + 0.1;
   267→
   268→            if (upperThreshold > 1.0)
   269→                upperThreshold = 1.0;
   270→        }
