   306→        private static string GenerateTextOutput(CodeSummary summary, string badgeUrl, bool indicators, bool hideBranchRate, bool hideComplexity)
   307→        {
   308→            StringBuilder textOutput = new();
   309→
   310→            if (!string.IsNullOrWhiteSpace(badgeUrl))
   311→            {
   312→                textOutput.AppendLine(badgeUrl)
   313→                          .AppendLine();
   314→            }
   315→
   316→            foreach (CodeCoverage package in summary.Packages)
   317→            {
   318→                textOutput.Append($"{package.Name}: Line Rate = {package.LineRate * 100:N0}%")
   319→                          .Append(hideBranchRate ? string.Empty : $", Branch Rate = {package.BranchRate * 100:N0}%")
   320→                          .Append(hideComplexity ? string.Empty : (package.Complexity % 1 == 0) ? $", Complexity = {package.Complexity}" : $", Complexity = {package.Complexity:N4}")
   321→                          .AppendLine(indicators ? $", {GenerateHealthIndicator(package.LineRate)}" : string.Empty);
   322→            }
   323→
   324→            textOutput.Append($"Summary: Line Rate = {summary.LineRate * 100:N0}% ({summary.LinesCovered} / {summary.LinesValid})")
   325→                      .Append(hideBranchRate ? string.Empty : $", Branch Rate = {summary.BranchRate * 100:N0}% ({summary.BranchesCovered} / {summary.BranchesValid})")
   326→                      .Append(hideComplexity ? string.Empty : (summary.Complexity % 1 == 0) ? $", Complexity = {summary.Complexity}" : $", Complexity = {summary.Complexity:N4}")
   327→                      .AppendLine(indicators ? $", {GenerateHealthIndicator(summary.LineRate)}" : string.Empty);
   328→
   329→            return textOutput.ToString();
   330→        }
   331→
   332→        private static string GenerateMarkdownOutput(CodeSummary summary, string badgeUrl, bool indicators, bool hideBranchRate, bool hideComplexity)
   333→        {
   334→            StringBuilder markdownOutput = new();
   335→
   336→            if (!string.IsNullOrWhiteSpace(badgeUrl))
   337→            {
   338→                markdownOutput.AppendLine($"![Code Coverage]({badgeUrl})")
   339→                              .AppendLine();
   340→            }
   341→
   342→            markdownOutput.Append("Package | Line Rate")
   343→                          .Append(hideBranchRate ? string.Empty : " | Branch Rate")
   344→                          .Append(hideComplexity ? string.Empty : " | Complexity")
   345→                          .AppendLine(indicators ? " | Health" : string.Empty)
   346→                          .Append("-------- | ---------")
   347→                          .Append(hideBranchRate ? string.Empty : " | -----------")
   348→                          .Append(hideComplexity ? string.Empty : " | ----------")
   349→                          .AppendLine(indicators ? " | ------" : string.Empty);
   350→
   351→            foreach (CodeCoverage package in summary.Packages)
   352→            {
   353→                markdownOutput.Append($"{package.Name} | {package.LineRate * 100:N0}%")
   354→                              .Append(hideBranchRate ? string.Empty : $" | {package.BranchRate * 100:N0}%")
   355→                              .Append(hideComplexity ? string.Empty : (package.Complexity % 1 == 0) ? $" | {package.Complexity}" : $" | {package.Complexity:N4}" )
   356→                              .AppendLine(indicators ? $" | {GenerateHealthIndicator(package.LineRate)}" : string.Empty);
   357→            }
   358→
   359→            markdownOutput.Append($"**Summary** | **{summary.LineRate * 100:N0}%** ({summary.LinesCovered} / {summary.LinesValid})")
   360→                          .Append(hideBranchRate ? string.Empty : $" | **{summary.BranchRate * 100:N0}%** ({summary.BranchesCovered} / {summary.BranchesValid})")
   361→                          .Append(hideComplexity ? string.Empty : (summary.Complexity % 1 == 0) ? $" | **{summary.Complexity}**" : $" | **{summary.Complexity:N4}**")
   362→                          .AppendLine(indicators ? $" | {GenerateHealthIndicator(summary.LineRate)}" : string.Empty);
   363→
   364→            return markdownOutput.ToString();
   365→        }
   366→    }
   367→}
